function check_increaseLiquidity_unauthorized(uint256 tokenId, uint256 amount0Desired, uint256 amount1Desired, address caller) public {
    vm.assume(tokenId > 0 && _exists(tokenId));
    address owner = ownerOf(tokenId);
    vm.assume(caller != owner);
    vm.assume(!isApprovedForAll(owner, caller));
    vm.assume(getApproved(tokenId) != caller);

    IncreaseLiquidityParams memory params = IncreaseLiquidityParams({
        tokenId: tokenId,
        amount0Desired: amount0Desired,
        amount1Desired: amount1Desired,
        amount0Min: 0,
        amount1Min: 0,
        deadline: block.timestamp + 1000
    });

    vm.prank(caller);
    try nonfungiblePositionManager.increaseLiquidity(params) {
        assert(false); // Should have reverted
    } catch {
        // Expected revert
    }
}
